mapper.select:
SELECT n.id, n.user_id, n.sender_id, n.type, n.title, n.content,
       n.target_id, n.target_type, n.is_read, n.create_time,
       u.nickname as sender_name, u.avatar as sender_avatar
FROM sys_notification n
LEFT JOIN sys_user u ON n.sender_id = u.id

    AND n.user_id = #{userId}
    AND n.type = #{type}
    AND n.is_read = #{isRead}

ORDER BY n.create_time DESC
